pragma solidity ^0.8.20;

contract Counter {
  uint256 public count = 1;
  bool public active = true;
}

pragma solidity ^0.8.20;

contract Math {
  function add(uint256 a, uint256 b) public pure returns (uint256) {
    return a + b;
  }
}

pragma solidity ^0.8.20;

contract Vault {
  address public owner;
  constructor() { owner = msg.sender; }

  function onlyOwnerAction() public view returns (bool) {
    require(msg.sender == owner, 'Not owner');
    return true;
  }
}

pragma solidity ^0.8.20;

contract Sum {
  function sumUpTo(uint256 n) public pure returns (uint256 s) {
    for (uint256 i = 1; i <= n; i++) {
      s += i;
    }
  }
}

pragma solidity ^0.8.20;

contract Store {
  uint256[] public nums;
  mapping(address => uint256) public score;

  function add(uint256 x) public { nums.push(x); }
}

pragma solidity ^0.8.20;

contract Tasks {
  enum Status { Pending, Done }
  struct Task { string title; Status status; }
  Task public t = Task('Learn Solidity', Status.Pending);
}

pragma solidity ^0.8.20;

contract Owned {
  address public owner = msg.sender;
  modifier onlyOwner() {
    require(msg.sender == owner, 'Not owner');
    _;
  }
}

pragma solidity ^0.8.20;

interface IGreeter { function greet() external pure returns (string memory); }
contract Greeter is IGreeter {
  function greet() external pure override returns (string memory) {
    return 'hello';
  }
}

pragma solidity ^0.8.20;

contract Logger {
  event Deposited(address indexed user, uint256 amount);
  function deposit() public payable {
    emit Deposited(msg.sender, msg.value);
  }
}

pragma solidity ^0.8.20;

error TooSmall(uint256 sent, uint256 min);

contract Pay {
  function buy() public payable {
    if (msg.value < 1 ether) revert TooSmall(msg.value, 1 ether);
  }
}

pragma solidity ^0.8.20;

contract Wallet {
  receive() external payable {}
  function balance() public view returns (uint256) { return address(this).balance; }
}

pragma solidity ^0.8.20;

contract SafeWithdraw {
  mapping(address => uint256) public bal;
  function deposit() public payable { bal[msg.sender] += msg.value; }
  function withdraw() public {
    uint256 a = bal[msg.sender];
    require(a > 0, 'none');
    bal[msg.sender] = 0;
    (bool ok,) = msg.sender.call{value: a}("");
    require(ok, 'fail');
  }
}
